drop table if exists TwentyOneTables CASCADE;
drop table if exists SlotMachinesOrders CASCADE;
drop table if exists SlotMachines CASCADE;
drop table if exists Casinos CASCADE;
drop table if exists PokerEvent CASCADE;
drop table if exists Bets CASCADE;

create table TwentyOneTables (
	id int,
	table_n int,
	card varchar(2)
);


-- Brynjolf the Thief --

create table PokerEvent(
    id int PRIMARY KEY,
    event_type text,
    executor text
);

create table Bets(
    id int PRIMARY KEY,
    poker_event_id int REFERENCES PokerEvent,
    value int
);







-- Alfonso Manada the Robber --

create table Casinos(
    id int PRIMARY KEY,
    name text,
    stars int
);

create table SlotMachines(
    id int PRIMARY KEY,
    earning_rate float
);

create table SlotMachinesOrders(
    id int PRIMARY KEY,
    event_date timestamp,
    event_type text,
    slot_machine_id int REFERENCES SlotMachines,
    casino_id int
);






	
  